tikzpicture[scale=0.6]
 % Grid
 (-1,-4) grid (9,5);
 (-1,0) – (9.5,0) node[right] {$x$};
 (0,-4) – (0,5.5) node[above] {$y$};

 % x-axis highlighted
 (-1,0) – (9,0);

 % Original point
 ll[AtlasTeal] (2,3) circle (4pt);
 at (2,3) {$P(2, 3)$};

 % After translation
 ll[gray] (7,3) circle (3pt);
 at (7,3) {$(7, 3)$};

 % Final image
 ll[AtlasWarm] (7,-3) circle (4pt);
 at (7,-3) {$P''(7, -3)$};

 % Arrows
 (2.3,3) – (6.7,3);
 (7,2.7) – (7,-2.7);
